import{_ as p}from"./nyalra_kb-7135827b.js";import{_ as l}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as m,a1 as d,C as a}from"./framework-a4c02b8f.js";const f={},h=e("figure",null,[e("img",{src:p,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),u={href:"https://tree-novel.com/works/episode/c0cd5bd9918b742ec009bf324214fca7.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>和别人聊天的时候，我们聊到「在网上大言不惭的账号的真实身份是什么呢」。像我们这样作为创作者在网上活动的人、艺人和政治家一定会看到它们。它们总是充满攻击性，喜欢中伤别人，是一群神秘的人。一言以蔽之，就是「他们应该很闲」。难得提到一次，就更深入地思考一下吧。因为，我和他们一样，也是很闲的人。</p><p>首先，尽管说「很闲」，但这种「很闲」与失业者一整天都无事可做的程度应该有所不同。我认识的一位成熟的主播制作人对此评价：就好像「每周工作五天后回家，喝着小酒刷着手机，慢悠悠地窥探着互联网」这种感觉的闲暇吧。换句话说，我认为是「虽然直到为第二天做好准备睡觉还有足够的时间，但由于还要上班，所以不能做复杂的事情，顶多只能刷刷手机看看电视」的状态。</p><p>疲惫不堪地结束令人不愉快的工作的一天，回到家。冰箱里有从超市囤积的冰啤酒。用微波炉加热一份烤鸡串拼盘，从酒精中获得一点点自我抚慰。可以用Switch玩塞尔达传说的新作，或者与朋友在LINE上通话，举行抱怨大会，这些都是不错的选择。但是一想到明天还要坐拥挤的电车，那种活力也会被削弱。好吧，那就看看手机吧！</p><p>然后不管是Yahoo新闻也好，还是Twitter也好。滚动浏览几分钟，追踪话题，每个晚上都会发生某种事件，名人或作品都在闹出笑话。酒精这种毒药侵害着大脑，感到愉快的此刻，读完综合新闻的感想是「这些人真是笨蛋」。哈哈哈。看着受欢迎的人因愚蠢的失误而毁了一生，感觉真是太爽了！这比满满浸泡在酱汁中的烤鸡串拼盘还要令人愉快！心情稍微好了一些。或者，也许会涌起义愤，说「这些坏家伙真不能原谅！」，尽管与自己无关。</p><p>无论如何，结果都是一样的，不久就会有人想发表一些言论。闲暇的人很难抗拒互联网的魔力。这是一种「对流行话题有话要说」的现象。特别是对于疲惫的社会人来说，那个触发点尤为轻微。他们可能会以略带傲慢的口吻写道：「这个白痴怎么会变得有名并赚麻了呢？这个国家已经完了。」「反正这家伙只想着钱和女人。」「这个国家又在浪费税金，不感到羞耻吗？」等等，以轻蔑的眼光评论，然后把今天的沙袋当成出气筒，摆脱工作压力。他们是邪恶的，而我们是守法的正义。没有任何问题。对方自食其果，善恶有报，嘲笑傻瓜又有什么不对呢。</p><p>发表了这些评论，感到神清气爽后，就任由酒精的气势昏倒。第二天，会忘记那些发帖，匆匆赶上电车。再次投入到无聊的工作之中，疲惫不堪，然后用酒和互联网上的一些话来治愈伤口。这就是日常。完全没有这之外的特殊用心，完全没有「人气者气人」之外的行动原理。只是这些评论积累下来，从旁观者的角度来看，他们会认为这是「总是在互联网上发火的糟糕账号」。然而，他们本人并不觉得自己经常生气。从根本上说，他们使用互联网的方式就不同，他们的网络观就是作为下酒菜，来消除对社会的不满的小小压力释放器。从这些人的角度来看，那些沉浸在互联网的人总是纠结于规矩和细小的规则，让人感到烦人无比。受害者明星的八卦消息可能是谣言也好，真相是另一个肇事者也好，这些都无关紧要。即使追求真相和合理性，烤鸡串也不会更美味。</p><p>但是，他们或她们每周工作五天，支撑着社会的运转。了不起。非常了不起。我以前的熟人，成为社会人后，不知不觉地变成了一个只对互联网上发表的话题评论一两句就走的账号。而且，有时他显得特别傲慢，言辞不准确。但他每天都在工作，直接支撑着人们的生活。为了避免具体情况，我就随便举个例子，比如他从事电线杆的维护工作。正因为他把城市的电线杆和电线连接在一起，所以居民家里才亮起了电。这是一项伟大的工作。</p><p>这样的他下班之后，在下一个工作日之前的短暂时间中刷刷手机，用一些随便的言论随随便便地加入某个话题，然后就这样入眠，很难因此责备他。他的发言毕竟只是当场的，不是纠缠不休，也不是恶意的反对行为，也没有恶毒到需要责备他说：「有人因为你的不负责任的发言受伤了！」。而且刻意追求这种规矩才是不正常的吧。因为，这种社会人很多。对他们来说，整天在互联网上进行「正确」的辩论的创作者和主播们才是闲人。无论我们把亚文化做得多么热闹，电力也并不会因此直接供应到其他人的家中。能够直接为他人提供帮助的人真的很了不起。</p><p>当然，我们也有话要说。亚文化和兴趣爱好的存在使人们的生活更加充实。如果没有这些小休息，人类就会变成一个机械，不断地重复工作、进食和睡眠。我写文章、制作游戏，确实能够拯救一些人。但从他们的角度来看，可能会觉得我们只是「在互联网上玩耍并拿钱」的人。</p><p>这也是一个没有明确答案的问题。我的继父也是，每次查看他的Twitter账户时，他总是一年四季都在转发政治批评内容，不断地与各种人争论。真的让我感到很震惊。我想，如果他有时间做这种事，不如带上我刚再婚的母亲去约会。但对他来说，在互联网上拿政治家当沙袋，让自己的心情愉快，也是一种很重要的支撑吧。毕竟，我的继父每周五天都在做美容师的工作，帮助他人。他支撑着我母亲的生活。</p><p>嘛，虽然我绝对不想成为那样的人就是了。 与其就这样向社会和劳动出卖灵魂，玷污自己，我宁愿在森林里默默地生活。</p><hr><p><img src="'+l+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/e7b05309a0fc7fcbb912a42414a5372a.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【万代『虫王战队君王者』蜘蛛行者完整套装】这是『虫王战队君王者』的追加战士，可以变身为蜘蛛行者的玩具套装。每个部分都嵌有蜘蛛图案，看起来非常酷。这种充满毒性颜色的神秘魅力对孩子们来说也很吸引人。说实话，就连我也已经迷上了蜘蛛行者。通过将蜘蛛和蜘蛛网与名字相结合，加入了「Dark」这个词......虽然简单，但这个创意让人感到兴奋。干得好，君王者.....</p></blockquote>',15);function g(x,y){const r=a("ExternalLinkIcon"),n=a("RouterLink");return s(),_("div",null,[i(" more "),h,e("p",null,[t("原文链接："),e("a",u,[t("第34回／普通にニュースに話すアカウント"),o(r)])]),e("blockquote",null,[k,e("p",null,[o(n,{to:"/posts/Translate/nyalra_kb_33.html"},{default:m(()=>[t("【奈亚拉面壁自语】第33回｜梦的控制【230704】")]),_:1})])]),b])}const L=c(f,[["render",g],["__file","nyalra_kb_34.html.vue"]]);export{L as default};
